import { Button } from "@repo/ui/components/ui/button";
import { JsonLd } from "@vendor/seo/json-ld";
import { ChevronLeft, ChevronRight } from "lucide-react";
import type { Metadata, Route } from "next";
import Image from "next/image";
import { notFound } from "next/navigation";
import { mdxComponents } from "~/app/(app)/(content)/_lib/mdx-components";
import {
  getChangelogPage,
  getChangelogPages,
} from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import { emitChangelogEntrySeo } from "~/lib/seo-bundle";
import type { ChangelogUrl } from "~/lib/url-types";

export const dynamic = "force-static";

interface Props {
  params: Promise<{ slug: string }>;
}

export async function generateStaticParams() {
  return getChangelogPages().map((page) => ({ slug: page.slugs[0] }));
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const page = getChangelogPage([slug]);
  if (!page) {
    return {};
  }
  const url = `https://lightfast.ai/changelog/${slug}` as ChangelogUrl;
  const { metadata } = emitChangelogEntrySeo(page.data, url);
  return metadata;
}

export default async function ChangelogEntryPage({ params }: Props) {
  const { slug } = await params;
  const page = getChangelogPage([slug]);
  if (!page) {
    notFound();
  }

  const url = `https://lightfast.ai/changelog/${slug}` as ChangelogUrl;
  const { jsonLd } = emitChangelogEntrySeo(page.data, url);
  const MDXContent = page.data.body;

  const {
    title,
    version,
    type,
    publishedAt,
    authors,
    tldr,
    ogImage,
    description,
  } = page.data;

  const allPages = getChangelogPages().sort(
    (a, b) =>
      new Date(b.data.publishedAt).getTime() -
      new Date(a.data.publishedAt).getTime()
  );
  const currentIndex = allPages.findIndex((p) => p.slugs[0] === slug);
  const prevEntry =
    currentIndex < allPages.length - 1 ? allPages[currentIndex + 1] : null;
  const nextEntry = currentIndex > 0 ? allPages[currentIndex - 1] : null;

  return (
    <>
      <JsonLd code={jsonLd} />
      <article className="space-y-3">
        <p className="text-muted-foreground text-sm">
          <Button
            asChild
            className="h-auto p-0 text-muted-foreground text-sm hover:text-foreground"
            variant="link"
          >
            <NavLink href="/changelog">Changelog</NavLink>
          </Button>
          {version ? <> / {version}</> : null}
        </p>

        <h2 className="pb-4 font-medium font-pp text-2xl">{title}</h2>

        <p className="font-mono text-muted-foreground text-xs uppercase tracking-wider">
          {type}
        </p>

        {ogImage &&
          ogImage !== "https://lightfast.ai/images/og-default.png" && (
            <div className="relative aspect-video w-full overflow-hidden rounded-lg bg-card">
              <Image
                alt={title}
                className="h-full w-full object-cover"
                fill
                priority
                src={ogImage}
              />
            </div>
          )}

        <p className="text-muted-foreground text-sm">
          {authors[0]?.name ?? "Lightfast"} Â·{" "}
          <time dateTime={publishedAt}>
            {new Date(publishedAt).toLocaleDateString(undefined, {
              year: "numeric",
              month: "short",
              day: "numeric",
            })}
          </time>
        </p>

        {tldr && (
          <div className="my-8 rounded-xs bg-card p-8">
            <h3 className="mb-4 font-mono font-semibold text-muted-foreground text-xs uppercase tracking-widest">
              TL;DR
            </h3>
            <p className="text-foreground/90 text-sm leading-relaxed">{tldr}</p>
          </div>
        )}

        {description && (
          <p className="pt-4 text-muted-foreground text-sm leading-relaxed">
            {description}
          </p>
        )}

        <div className="mt-8 max-w-none">
          <MDXContent components={mdxComponents} />
        </div>

        {(prevEntry ?? nextEntry) && (
          <nav
            aria-label="Changelog navigation"
            className="grid grid-cols-1 gap-4 pt-8 md:grid-cols-2"
          >
            {prevEntry ? (
              <NavLink
                className="group"
                href={`/changelog/${prevEntry.slugs[0]}` as Route}
                prefetch
              >
                <div className="h-full rounded-sm border border-transparent bg-card p-4 transition-all duration-200 hover:border-muted-foreground/20 hover:bg-accent/5">
                  <span className="flex items-center gap-1 text-muted-foreground text-sm">
                    <ChevronLeft className="h-4 w-4" />
                    Previous post
                  </span>
                  <span className="mt-1 line-clamp-2 block font-medium text-foreground text-sm">
                    {prevEntry.data.title}
                  </span>
                </div>
              </NavLink>
            ) : (
              <div />
            )}
            {nextEntry ? (
              <NavLink
                className="group md:text-right"
                href={`/changelog/${nextEntry.slugs[0]}` as Route}
                prefetch
              >
                <div className="h-full rounded-sm border border-transparent bg-card p-4 transition-all duration-200 hover:border-muted-foreground/20 hover:bg-accent/5">
                  <span className="flex items-center justify-end gap-1 text-muted-foreground text-sm">
                    Next post
                    <ChevronRight className="h-4 w-4" />
                  </span>
                  <span className="mt-1 line-clamp-2 block font-medium text-foreground text-sm">
                    {nextEntry.data.title}
                  </span>
                </div>
              </NavLink>
            ) : (
              <div />
            )}
          </nav>
        )}
      </article>
    </>
  );
}

import { z } from "zod";

const AuthorSchema = z.object({
  name: z.string().min(1),
  url: z.url(),
  twitterHandle: z.string().min(1),
});

const FaqItemSchema = z.object({
  question: z.string().min(10),
  answer: z.string().min(20),
});

const BasePageSchema = z.object({
  title: z.string().min(1),
  description: z.string().min(50).max(160),
  keywords: z.array(z.string().min(1)).min(3).max(20),
  canonicalUrl: z.url(),
  ogTitle: z.string().min(1).max(70),
  ogDescription: z.string().min(50).max(160),
  ogImage: z.url(),
  noindex: z.boolean().default(false),
  nofollow: z.boolean().default(false),
});

const ContentPageSchema = BasePageSchema.extend({
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  faq: z.array(FaqItemSchema).min(1),
});

export const BlogPostSchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/blog/"))
    .optional(),
  category: z.enum([
    "engineering",
    "product",
    "company",
    "tutorial",
    "research",
  ]),
  readingTimeMinutes: z.number().int().min(1),
  featured: z.boolean().default(false),
  tldr: z.string().min(20).max(300),
});

export const ChangelogEntrySchema = ContentPageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/changelog/"))
    .optional(),
  version: z.string().min(1),
  type: z.enum(["feature", "improvement", "fix", "breaking"]),
  tldr: z.string().min(20).max(300),
});

export const LegalPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/legal/"))
    .optional(),
  updatedAt: z.iso.datetime(),
  effectiveAt: z.iso.datetime(),
});

export const DocsPageSchema = BasePageSchema.extend({
  canonicalUrl: z
    .url()
    .refine((val) => val.startsWith("https://lightfast.ai/docs/"))
    .optional(),
  authors: z.array(AuthorSchema).min(1),
  publishedAt: z.iso.datetime(),
  updatedAt: z.iso.datetime(),
  proficiencyLevel: z
    .enum(["Beginner", "Intermediate", "Advanced", "Expert"])
    .optional(),
});

// Inferred TypeScript types
export type BlogPostData = z.infer<typeof BlogPostSchema>;
export type ChangelogEntryData = z.infer<typeof ChangelogEntrySchema>;
export type LegalPageData = z.infer<typeof LegalPageSchema>;
export type DocsPageData = z.infer<typeof DocsPageSchema>;

// Fields required by the SEO layer â€” satisfied structurally by BlogPostData,
// ChangelogEntryData, and DocsPageData. Derived from BlogPostData so schema
// renames propagate here automatically.
export type ContentSeoData = Pick<
  BlogPostData,
  | "authors"
  | "description"
  | "keywords"
  | "nofollow"
  | "noindex"
  | "ogDescription"
  | "ogImage"
  | "ogTitle"
  | "publishedAt"
  | "title"
  | "updatedAt"
>;

// Derived from Zod â€” Zod is the sole source of truth for these unions
export type BlogCategory = BlogPostData["category"];
// â†’ "engineering" | "product" | "company" | "tutorial" | "research"

export type ChangelogType = ChangelogEntryData["type"];
// â†’ "feature" | "improvement" | "fix" | "breaking"

import type { GraphContext } from "@vendor/seo/json-ld";
import type { Metadata } from "next";
import type { Crumb } from "./builders";
import {
  buildApiRefJsonLd,
  buildBlogPostJsonLd,
  buildChangelogEntryJsonLd,
  buildDocsJsonLd,
  buildLegalJsonLd,
} from "./builders";
import type {
  BlogPostData,
  ChangelogEntryData,
  ContentSeoData,
  DocsPageData,
  LegalPageData,
} from "./content-schemas";
import { createArticleMetadata, createMetadata } from "./content-seo";
import type {
  ApiRefUrl,
  BlogPostUrl,
  ChangelogUrl,
  DocsUrl,
  LegalUrl,
} from "./url-types";

interface SeoBundle {
  readonly jsonLd: GraphContext;
  readonly metadata: Metadata;
}

// SeoBundle owns canonical URL derivation â€” derives from the typed url param,
// respects frontmatter canonicalUrl as an escape hatch.
// Both metadata.alternates.canonical and JSON-LD url come from the same value:
// drift is structurally impossible.

function buildArticleMetadata(
  data: ContentSeoData,
  canonicalUrl: string,
  titleSuffix: string,
  siteName: string
): Metadata {
  return createArticleMetadata(
    {
      title: `${data.title} â€“ ${titleSuffix}`,
      description: data.description,
      keywords: data.keywords,
      authors: data.authors.map((a) => ({ name: a.name, url: a.url })),
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        url: canonicalUrl,
        siteName,
        locale: "en_US",
        images: [
          { url: data.ogImage, width: 1200, height: 630, alt: data.ogTitle },
        ],
        authors: data.authors.map((a) => a.url),
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        images: [data.ogImage],
      },
      category: "Technology",
    },
    { publishedAt: data.publishedAt, updatedAt: data.updatedAt }
  );
}

export function emitBlogPostSeo(
  data: BlogPostData,
  url: BlogPostUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Blog",
      "Lightfast Blog"
    ),
    jsonLd: buildBlogPostJsonLd(data, url),
  };
}

export function emitChangelogEntrySeo(
  data: ChangelogEntryData,
  url: ChangelogUrl
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Changelog",
      "Lightfast Changelog"
    ),
    jsonLd: buildChangelogEntryJsonLd(data, url),
  };
}

export function emitDocsSeo(
  data: DocsPageData,
  url: DocsUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: buildArticleMetadata(
      data,
      canonicalUrl,
      "Lightfast Docs",
      "Lightfast Documentation"
    ),
    jsonLd: buildDocsJsonLd(data, url, breadcrumbs),
  };
}

export function emitLegalSeo(data: LegalPageData, url: LegalUrl): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
    metadata: createMetadata({
      title: `${data.title} â€“ Lightfast`,
      description: data.description,
      keywords: data.keywords,
      creator: "Lightfast",
      publisher: "Lightfast",
      robots: {
        index: !data.noindex,
        follow: !data.nofollow,
        googleBot: {
          index: !data.noindex,
          follow: !data.nofollow,
          "max-video-preview": -1,
          "max-image-preview": "large",
          "max-snippet": -1,
        },
      },
      alternates: { canonical: canonicalUrl },
      openGraph: {
        title: data.ogTitle,
        description: data.ogDescription,
        type: "website",
        url: canonicalUrl,
        siteName: "Lightfast",
        locale: "en_US",
        images: [
          { url: data.ogImage, width: 1200, height: 630, alt: data.ogTitle },
        ],
      },
      twitter: {
        card: "summary_large_image",
        title: data.ogTitle,
        description: data.ogDescription,
        site: "@lightfastai",
        creator: "@lightfastai",
        images: [data.ogImage],
      },
    }),
    jsonLd: buildLegalJsonLd(data, url),
  };
}

export function emitApiRefSeo(
  data: DocsPageData,
  url: ApiRefUrl,
  breadcrumbs: Crumb[]
): SeoBundle {
  const canonicalUrl = data.canonicalUrl ?? url;
  return {
