22	 * Merges page metadata with application-level defaults.
23	 * Pages construct their own title, description, openGraph, etc.
24	 * and this function injects the common base (applicationName, metadataBase, etc.).
25	 */
26	export function createMetadata(
27	  metadata: Partial<Metadata>,
28	  overrides?: Partial<Metadata>
29	): Metadata {
30	  return merge({}, appDefaults, metadata, overrides ?? {});
31	}
32	
33	/**
34	 * Like createMetadata but forces og:type to "article" with publish/modify times.
35	 * Use for blog posts and changelog entries.
36	 */
37	export function createArticleMetadata(
38	  metadata: Partial<Metadata>,
39	  times: { publishedAt: string; updatedAt: string },
40	  overrides?: Partial<Metadata>
41	): Metadata {
42	  return createMetadata(
43	    metadata,
44	    merge(
45	      {
46	        openGraph: {
47	          type: "article" as const,
48	          publishedTime: times.publishedAt,
49	          modifiedTime: times.updatedAt,
50	        },
51	      },
52	      overrides ?? {}
53	    )
54	  );
