import merge from "lodash.merge";
import type { Metadata } from "next";

const applicationName = "Lightfast";
const protocol = process.env.NODE_ENV === "production" ? "https" : "http";
const productionUrl = seoEnv.VERCEL_PROJECT_PRODUCTION_URL;

const appDefaults: Metadata = {
  applicationName,
  metadataBase: productionUrl
    ? new URL(`${protocol}://${productionUrl}`)
    : undefined,
  formatDetection: { telephone: false },
  appleWebApp: {
    capable: true,
    statusBarStyle: "default",
  },
};

/**
 * Merges page metadata with application-level defaults.
 * Pages construct their own title, description, openGraph, etc.
 * and this function injects the common base (applicationName, metadataBase, etc.).
 */
export function createMetadata(
  metadata: Partial<Metadata>,
  overrides?: Partial<Metadata>
): Metadata {
  return merge({}, appDefaults, metadata, overrides ?? {});
}

/**
 * Like createMetadata but forces og:type to "article" with publish/modify times.
 * Use for blog posts and changelog entries.
 */
export function createArticleMetadata(
  metadata: Partial<Metadata>,
  times: { publishedAt: string; updatedAt: string },
  overrides?: Partial<Metadata>
): Metadata {
  return createMetadata(
    metadata,
    merge(
      {
        openGraph: {
          type: "article" as const,
          publishedTime: times.publishedAt,
          modifiedTime: times.updatedAt,
        },
      },
      overrides ?? {}
    )
  );
}

import type { BlogPosting, GraphContext } from "@vendor/seo/json-ld";
import type { ChangelogEntryData, ChangelogType } from "~/lib/content-schemas";
import type { ChangelogUrl } from "~/lib/url-types";
import {
  buildBreadcrumbList,
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "./shared";

// Exhaustive mapping â€” adding a new ChangelogType errors here until handled
const CHANGELOG_SECTIONS: Record<ChangelogType, string> = {
  feature: "Changelog / Feature",
  improvement: "Changelog / Improvement",
  fix: "Changelog / Fix",
  breaking: "Changelog / Breaking Change",
};

function buildChangelogEntryEntity(
  data: ChangelogEntryData
): Omit<BlogPosting, "@id" | "url"> {
  return {
    "@type": "BlogPosting",
    headline: data.title,
    description: data.description,
    abstract: data.tldr,
    datePublished: data.publishedAt,
    dateModified: data.updatedAt,
    author: data.authors.map((a) => ({
      "@type": "Person" as const,
      name: a.name,
      url: a.url,
      sameAs: [`https://x.com/${a.twitterHandle.replace(/^@/, "")}`],
    })),
    image: {
      "@type": "ImageObject" as const,
      url: data.ogImage,
      width: "1200",
      height: "630",
    },
    keywords: [...data.keywords, data.version, data.type].join(", "),
    articleSection: CHANGELOG_SECTIONS[data.type],
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
  };
}

export function buildChangelogEntryJsonLd(
  data: ChangelogEntryData,
  url: ChangelogUrl
): GraphContext {
  const entity = buildChangelogEntryEntity(data);
  return {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      { ...entity, "@id": `${url}#article`, url },
      ...(data.faq.length > 0 ? [buildFaqEntity(data.faq, url)] : []),
      buildBreadcrumbList([
        { name: "Home", url: "https://lightfast.ai" },
        { name: "Changelog", url: "https://lightfast.ai/changelog" },
        { name: data.title, url },
      ]),
    ],
  };
}

